// This code uses Regular Expressions and adds emojis and better formatting.

// Helper function to get an emoji for a currency name
function getCurrencyEmoji(currencyName) {
  if (currencyName.includes('دولار')) return '🇺🇸';
  if (currencyName.includes('يورو')) return '🇪🇺';
  if (currencyName.includes('ريال')) return '🇸🇦';
  if (currencyName.includes('درهم')) return '🇦🇪';
  if (currencyName.includes('استرليني')) return '🇬🇧';
  return '💰'; // A default emoji
}

// Helper function to remove all HTML tags from a string
function cleanText(htmlString) {
  if (!htmlString) return '';
  return htmlString.replace(/<[^>]*>/g, '').trim();
}


// --- Main Script ---
const goldHtml = items[0].json.gold_prices;
const currencyHtml = items[0].json.currency_rates;
let messageLines = [];

// --- 1. Process Gold Prices ---
messageLines.push("🥇 *أسعار الذهب اليوم في مصر* 🥇");
messageLines.push("〰️〰️〰️〰️〰️〰️〰️〰️〰️〰️〰️");

const goldRows = goldHtml.match(/<tr.*?>.*?<\/tr>/gs) || [];

for (const row of goldRows) {
  const cells = row.match(/<td.*?>.*?<\/td>/gs) || [];

  if (cells.length > 0) {
    const type = cleanText(cells[0]);
    let emoji = '⚖️';
    if (type.includes('الجنيه الذهب')) emoji = '🪙';
    if (type.includes('العالمي')) emoji = '🌍';

    if (cells.length > 2) {
      const sellPrice = cleanText(cells[1]).replace(' جنيه', '');
      const buyPrice = cleanText(cells[2]).replace(' جنيه', '');
      messageLines.push(`${emoji} *${type}:* شراء \`${buyPrice}\` / بيع \`${sellPrice}\``);
    } else if (cells.length === 2) {
      const priceText = cleanText(cells[1]);
      const price = priceText.replace(/[^0-9.]/g, ''); // Extract only numbers
      const currency = priceText.includes('دولار') ? 'دولار' : 'جنيه';
      messageLines.push(`${emoji} *${type}:* \`${price}\` ${currency}`);
    }
  }
}

// --- 2. Process Currency Rates ---
messageLines.push("\n-----------------------------------\n");
messageLines.push("💸 *أسعار العملات (السوق الرسمي)* 💸");
messageLines.push("〰️〰️〰️〰️〰️〰️〰️〰️〰️〰️〰️");

const currencyRows = currencyHtml.match(/<tr.*?>.*?<\/tr>/gs) || [];

for (const row of currencyRows) {
  const cells = row.match(/<td.*?>.*?<\/td>/gs) || [];

  if (cells.length === 2) {
    const currencyName = cleanText(cells[0]);
    const currencyPrice = cleanText(cells[1]).replace(' جنيه', '');
    const emoji = getCurrencyEmoji(currencyName);
    messageLines.push(`${emoji} *${currencyName}:* \`${currencyPrice}\` جنيه`);
  }
}

// --- 3. Add a Timestamp ---
const now = new Date();
const timeString = now.toLocaleTimeString('ar-EG', { timeZone: 'Africa/Cairo', hour: '2-digit', minute:'2-digit' });
messageLines.push("\n`" + `تحديث: ${timeString} بتوقيت القاهرة` + "`");

const finalMessage = messageLines.join('\n');

return [{
  json: {
    telegram_message: finalMessage
  }
}];
